input.command:
$source = "C:\Users\016551\.agents\skills"
$dest = "C:\Users\016551\.cursor\skills"
$folders = Get-ChildItem -Directory $source
foreach ($f in $folders) {
    $target = Join-Path $dest $f.Name
    if (-not (Test-Path $target)) {
        Copy-Item -Recurse $f.FullName $target
        Write-Host "Copied: $($f.Name)"
    } else {
        Write-Host "Skipped (exists): $($f.Name)"
    }
}
Write-Host "Done. Total marketing skills copied: $($folders.Count)"
